+    let stripped: Vec<u8>;
+    let executed_script: &[u8] = if script.starts_with(b"#!") {
+        let line_end = script
+            .iter()
+            .position(|&b| b == b'\n')
+            .unwrap_or(script.len());
+        let mut tmp = Vec::with_capacity(script.len());
+        tmp.extend(std::iter::repeat_n(b' ', line_end));
+        tmp.extend_from_slice(&script[line_end..]);
+        stripped = tmp;
+        &stripped
+    } else {
